const crypto = require('crypto');
const secret = $env.SYNCSCRIPT_WEBHOOK_SECRET || '';
const rawBody = $input.first().binary?.data ? $input.first().binary.data.toString('utf8') : JSON.stringify($input.first().json || {});
const sig = String($input.first().headers?.['x-syncscript-signature'] || '').replace(/^sha256=/, '');
const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
if (!secret) throw new Error('Missing SYNCSCRIPT_WEBHOOK_SECRET');
if (!crypto.timingSafeEqual(Buffer.from(sig,'hex'), Buffer.from(expected,'hex'))) throw new Error('Invalid signature');
const j = $input.first().json;
const urgent = j.event_type === 'task.created' && String(j.payload?.priority || '').toLowerCase() === 'urgent';
const failed = j.event_type === 'playbook.run.failed';
if (!urgent && !failed) return [];
return j;

